// Unit 5: Static Testing (Chapter 6, pp.93–98)
EXTRA_UNITS.push({
id:5, concepts:[
{title:"🎯 Learning Objectives",ref:"Module 5",content:`<p>By the end of this chapter you should be able to:</p><ul><li>Examine the <strong>necessity</strong> of testing ALL documentation produced by a software project</li><li>List the <strong>variety</strong> of development documentation that should be tested</li><li>Describe the <strong>techniques</strong> for testing software development documentation</li><li>Apply <strong>static analysis</strong> tools to catch defects in code without executing it</li></ul><div class="zh-note">本章目标：理解为什么所有文档都要静态测试 · 知道有哪些类型的文档 · 掌握 5 种审查技术 · 会用静态分析工具找代码缺陷。</div>`},
{title:"📄 What is Static Testing?",ref:"pp.93",content:`<p><span class="key-term">Static testing</span> = testing <strong>documents and code WITHOUT executing</strong> the software. The word "static" literally means <em>"not running"</em>.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);">Aspect</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Static Testing</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">⏰ When</td><td style="padding:6px 8px;">Early — requirements, design, code (BEFORE running anything)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🎯 Focus</td><td style="padding:6px 8px;">Find defects in <strong>documentation + code logic</strong> before execution</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">💰 Cost</td><td style="padding:6px 8px;">CHEAPEST of all testing approaches</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:600;">📈 Potential</td><td style="padding:6px 8px;">LARGEST defect-reduction potential per dollar spent</td></tr></tbody></table><div class="callout important"><strong>Key insight:</strong> Static testing is the <strong>least expensive</strong> form of testing, yet has the <strong>largest potential</strong> for reducing defects. Why? Fixing a doc error early prevents 10 code errors later (recall Boehm's Rule from Unit 1).</div><p><strong>Primary goal:</strong> Reduce software defects by reducing <em>documentation</em> defects upstream.<br><strong>Secondary goal:</strong> Ensure correct system operation — many projects fail not from bad code but from incomprehensible docs.</p><div class="zh-note">静态测试 = 不运行代码，只审文档和代码。早期做，最便宜，效果最好。修一个文档错误能预防 10 个代码错误。</div>`},
{title:"⭐ 5 Benefits with LMS Examples",ref:"Module 5",content:`<p>Five concrete benefits — each grounded in a Library Management System (LMS) example.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Benefit</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">LMS Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">1</td><td style="padding:6px 8px;"><strong>Early defect detection</strong></td><td style="padding:6px 8px;font-style:italic;">Missing rule "max 5 books per student" found in SRS before coding</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">2</td><td style="padding:6px 8px;"><strong>Reduced timeline</strong></td><td style="padding:6px 8px;font-style:italic;">User manual reviewed → librarians can actually understand issue/return flow</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">3</td><td style="padding:6px 8px;"><strong>Reduced cost &amp; time</strong></td><td style="padding:6px 8px;font-style:italic;">Uninitialized var <code>bookCount</code> caught by static analysis — no runtime debugging</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--green);">4</td><td style="padding:6px 8px;"><strong>Improved productivity</strong></td><td style="padding:6px 8px;font-style:italic;">Tools flag book-reservation module issues → devs fix without running system</td></tr><tr><td style="padding:6px 8px;font-weight:700;color:var(--green);">5</td><td style="padding:6px 8px;"><strong>Fewer late-stage defects</strong></td><td style="padding:6px 8px;font-style:italic;">SQL injection in librarian-login caught early → no failure during system test</td></tr></tbody></table><div class="callout">All 5 benefits compound: catching one defect early = preventing potentially dozens of cascading downstream defects.</div><div class="zh-note">5 大好处：早发现 · 缩短工期 · 省钱省时 · 提升效率 · 减少后期 bug。每条都有图书馆例子。</div>`},
{title:"📋 What Gets Tested: 8 Features + 5 Doc Categories",ref:"pp.94–96 + Module 5",content:`<p>Static testing covers far more than just requirements documents. Module 5 lists 8 specific artifacts.</p><p><strong>🎯 8 Features tested by static testing:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Artifact</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">What's checked</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Unit Test Cases</td><td style="padding:6px 8px;">Complete? Follow standards?</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Business Requirements Doc (BRD)</td><td style="padding:6px 8px;">Clear? Aligns with stakeholders?</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Use Cases</td><td style="padding:6px 8px;">Accurately represent user interactions?</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Prototype</td><td style="padding:6px 8px;">Matches main design + functionality?</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">System Requirements</td><td style="padding:6px 8px;">Complete + accurate?</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">Test Data</td><td style="padding:6px 8px;">Covers all input scenarios?</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">⭐ Traceability Matrix</td><td style="padding:6px 8px;">All requirements mapped to test cases?</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:600;">Training Guides</td><td style="padding:6px 8px;">Accurately reflect system + user procedures?</td></tr></tbody></table><p><strong>📚 5 Categories of Candidate Documents (by author role):</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);width:35%;">📋 Manager docs</td><td style="padding:6px 8px;">Software requirements, project plans</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">💻 Developer docs</td><td style="padding:6px 8px;">Use cases, designs, specs, DFDs, DB designs, screen/report specs, <strong>source code</strong></td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">🧪 Tester docs</td><td style="padding:6px 8px;">Test plans, cases, environment specs, data sources</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">⚙️ Admin docs</td><td style="padding:6px 8px;">Installation guides, operation/admin guides</td></tr><tr><td style="padding:6px 8px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">👤 End-user docs</td><td style="padding:6px 8px;">User guides, help screens, training manuals</td></tr></tbody></table><div class="zh-note">8 类被测产物 + 5 类按角色分的文档。注意：代码本身也是开发者文档，照样要静态测。</div>`},
{title:"🔍 3 Review Focus Areas: Completeness · Consistency · Scope",ref:"Module 5",content:`<p>When reviewing any document, focus on these 3 dimensions. Skip any one and defects slip through.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:8px;text-align:left;color:var(--accent-dim);width:30%;">Focus Area</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">Question</th><th style="padding:8px;text-align:left;color:var(--accent-dim);">LMS Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:8px;color:var(--blue);font-weight:600;">✅ Completeness</td><td style="padding:8px;">"Does it cover ALL requirements?"</td><td style="padding:8px;font-style:italic;">Every requirement must reach design, test cases, AND user manual</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:8px;color:var(--purple);font-weight:600;">🔀 Consistency</td><td style="padding:8px;">"Do documents agree?"</td><td style="padding:8px;font-style:italic;">SRS: max 5 books · User guide: max 10 books → CONFLICT!</td></tr><tr><td style="padding:8px;color:var(--orange);font-weight:600;">📏 Scope Validation</td><td style="padding:8px;">"Are there unrequested features?"</td><td style="padding:8px;font-style:italic;">"Book Purchase" feature appears in design but wasn't requested → SCOPE CREEP</td></tr></tbody></table><div class="callout important">A document can be 100% complete and consistent but still <strong>out of scope</strong> (adding things nobody asked for) → wasted effort. All 3 must pass.</div><div class="zh-note">3 大审查维度：完整(没漏要求)·一致(文档之间不矛盾)·范围(没乱加东西)。三者缺一不可。</div>`},
{title:"👥 5 Review Techniques Compared",ref:"pp.96–98 + Module 5",content:`<p>Module 5 expands the textbook's 3 techniques to <strong>5</strong> by adding <strong>Informal Review</strong> and <strong>Peer Review</strong>.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:11.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px;text-align:left;color:var(--accent-dim);">Technique</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">Who</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">Formality</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">Purpose</th><th style="padding:6px;text-align:left;color:var(--accent-dim);">LMS Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;color:var(--blue);font-weight:600;">📤 Informal Review</td><td style="padding:6px;">BA / Dev / Tester sends doc to team</td><td style="padding:6px;">Low</td><td style="padding:6px;">Quick feedback, early defect detection</td><td style="padding:6px;font-style:italic;">BA shares SRS → dev finds missing login req</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px;color:var(--purple);font-weight:600;">🚶 Walkthrough</td><td style="padding:6px;">Team (structured meeting)</td><td style="padding:6px;">High</td><td style="padding:6px;">Step-by-step review for logic/req gaps</td><td style="padding:6px;font-style:italic;">Team finds no rule for "what if book already issued"</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px;color:var(--green);font-weight:600;">👫 Peer Review</td><td style="padding:6px;">One teammate reviews another's work</td><td style="padding:6px;">Medium</td><td style="padding:6px;">Systematic defect detection + compliance</td><td style="padding:6px;font-style:italic;">Dev finds missing late-fee calc rule in SRS</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px;color:var(--red);font-weight:600;">🔍 Inspection</td><td style="padding:6px;">Trained reviewers / senior staff (independent)</td><td style="padding:6px;">Very High (formal)</td><td style="padding:6px;">Rigorous accuracy + completeness check</td><td style="padding:6px;font-style:italic;">QA mgr finds inconsistent borrowing limit in SRS</td></tr><tr><td style="padding:6px;color:var(--orange);font-weight:600;">📝 Desk Checking</td><td style="padding:6px;">Author (SELF-review)</td><td style="padding:6px;">Very Low</td><td style="padding:6px;">Catch obvious mistakes before sharing</td><td style="padding:6px;font-style:italic;">BA finds missing book-renewal rule while reviewing own SRS</td></tr></tbody></table><div class="callout"><strong>Critical:</strong> Desk Checking is the ONLY technique where the <em>author tests their own document</em>. All others use independent reviewers.</div><div class="callout important"><strong>Two-step approach:</strong> ① Cosmetic cleanup (spell/grammar/format) first — otherwise reviewers proofread instead of reviewing content. ② Then apply one of the 5 techniques above for content review.</div><div class="zh-note">5 种技术按正式度：桌检(自审)→非正式(分享)→同行(互查)→走查(团队会议)→检视(独立专家)。越正式越费时但效果越好。</div>`},
{title:"🤖 Static Analysis: 3 Types + 5 Defects Detected",ref:"Module 5",content:`<p><span class="key-term">Static analysis</span> = examining <strong>source code WITHOUT executing it</strong>, usually via automated tools. Catches issues humans miss.</p><p><strong>🔬 3 Types of Static Analysis:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Type</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Checks</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--blue);font-weight:600;">📊 Data Flow</td><td style="padding:6px 8px;">How data moves: initialized → assigned → used</td><td style="padding:6px 8px;font-style:italic;">Variable used before being assigned</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;color:var(--purple);font-weight:600;">🔀 Control Flow</td><td style="padding:6px 8px;">Order of execution: branches, loops</td><td style="padding:6px 8px;font-style:italic;">Loop that never terminates, code that never runs</td></tr><tr><td style="padding:6px 8px;color:var(--orange);font-weight:600;">🔢 Cyclomatic Complexity</td><td style="padding:6px 8px;">Counts independent paths through code</td><td style="padding:6px 8px;font-style:italic;">More if/else → higher complexity → more tests needed</td></tr></tbody></table><p><strong>🐛 5 Defects Static Analysis Catches:</strong></p><div style="display:grid;grid-template-columns:repeat(5,1fr);gap:6px;margin:10px 0;font-size:11.5px;text-align:center;">
<div style="background:var(--red-bg);padding:10px 6px;border-radius:8px;border:2px solid var(--red);"><div style="font-size:22px;margin-bottom:4px;">📭</div><strong>Unused variables</strong></div>
<div style="background:var(--orange-bg);padding:10px 6px;border-radius:8px;border:2px solid var(--orange);"><div style="font-size:22px;margin-bottom:4px;">💀</div><strong>Dead code</strong></div>
<div style="background:var(--purple-bg);padding:10px 6px;border-radius:8px;border:2px solid var(--purple);"><div style="font-size:22px;margin-bottom:4px;">♾️</div><strong>Infinite loops</strong></div>
<div style="background:var(--blue-bg);padding:10px 6px;border-radius:8px;border:2px solid var(--blue);"><div style="font-size:22px;margin-bottom:4px;">❓</div><strong>Undefined value vars</strong></div>
<div style="background:var(--green-bg);padding:10px 6px;border-radius:8px;border:2px solid var(--green);"><div style="font-size:22px;margin-bottom:4px;">🔤</div><strong>Wrong syntax</strong></div>
</div><div class="callout"><strong>Cyclomatic complexity tip:</strong> if your code has CC = 4, you need at least 4 test cases for full branch coverage. Higher CC = harder to test = consider refactoring.</div><div class="zh-note">静态分析 3 类：数据流(变量怎么变)·控制流(代码走哪条路)·圈复杂度(几条独立路径)。能抓 5 种缺陷：未用变量·死代码·死循环·未初始化·语法错误。</div>`},
{title:"📈 How Static Testing is Performed (7 Steps)",ref:"Module 5",content:`<p>The standard process — applied to a <strong>Student Registration System (SRS)</strong> example.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Step</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">SRS Example</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">1</td><td style="padding:6px 8px;"><strong>Planning</strong></td><td style="padding:6px 8px;font-style:italic;">Define objectives, scope, strategy for static testing</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">2</td><td style="padding:6px 8px;"><strong>Prepare Artifacts</strong></td><td style="padding:6px 8px;font-style:italic;">Focus on registration rules: prerequisites, max 5 courses</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">3</td><td style="padding:6px 8px;"><strong>Collect Documents</strong></td><td style="padding:6px 8px;font-style:italic;">SRS, designs, use cases, source code, test cases</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">4</td><td style="padding:6px 8px;"><strong>Perform Static Analysis</strong></td><td style="padding:6px 8px;font-style:italic;">Tools detect uninitialized <code>availableSeats</code>, dead code</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">5</td><td style="padding:6px 8px;"><strong>Perform Code Reviews</strong></td><td style="padding:6px 8px;font-style:italic;">Manual check finds: course limit = 6 (should be 5)</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;color:var(--accent);">6</td><td style="padding:6px 8px;"><strong>Report Bugs</strong></td><td style="padding:6px 8px;font-style:italic;">Document all defects in tracker (Jira) for correction</td></tr><tr><td style="padding:6px 8px;font-weight:700;color:var(--accent);">7</td><td style="padding:6px 8px;"><strong>Analyze Results</strong></td><td style="padding:6px 8px;font-style:italic;">10 req defects · 5 code defects · 3 business logic defects</td></tr></tbody></table><div class="callout"><strong>Typical findings split:</strong> ~⅓ requirements defects · ~⅓ code defects · ~⅓ business logic defects. Track all 3 categories.</div><div class="zh-note">7 步标准流程：规划 → 准备产物 → 收集文档 → 跑静态分析工具 → 人工审代码 → 报 bug → 分析结果。SRS 例子贯穿全部 7 步。</div>`},
{title:"🛠️ Modern Static Testing Tools",ref:"Module 5",content:`<p>The tooling landscape (2026). Most modern teams use 2-3 of these together.</p><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Tool</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Language / Focus</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">What It Catches</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">☕ Checkstyle</td><td style="padding:6px 8px;">Java</td><td style="padding:6px 8px;">Coding standards + formatting</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🐍 Pylint</td><td style="padding:6px 8px;">Python</td><td style="padding:6px 8px;">Style violations + logical errors</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🔍 Lint</td><td style="padding:6px 8px;">C / generic</td><td style="padding:6px 8px;">Programming errors without execution</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">🛡️ Bandit</td><td style="padding:6px 8px;">Python security</td><td style="padding:6px 8px;">Hardcoded passwords, SQL injection patterns</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">📜 ESLint</td><td style="padding:6px 8px;">JavaScript / TypeScript</td><td style="padding:6px 8px;">Syntax + style + quality issues</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:600;">📊 SonarQube</td><td style="padding:6px 8px;">25+ languages</td><td style="padding:6px 8px;">Bugs + vulnerabilities + code smells + tech debt</td></tr></tbody></table><div class="callout important"><strong>Modern reality:</strong> These tools run AUTOMATICALLY on every PR via CI/CD (GitHub Actions, GitLab CI). Bad code never reaches main branch. The 2007 idea of "running Pylint manually" is now "Pylint runs in 3 seconds when you save a file in VS Code".</div><div class="zh-note">现代工具：Pylint(Python)·ESLint(JS)·Checkstyle(Java)·Bandit(安全)·SonarQube(企业级)。都在 CI/CD 里自动跑，写代码时 IDE 也实时提示。</div>`},
{title:"⚖️ Benefits vs Limitations + 7 Best Practices",ref:"Module 5",content:`<table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:12.5px;"><thead><tr><th style="padding:8px;text-align:left;background:var(--green-bg);color:var(--green);font-weight:700;border-bottom:2px solid var(--green);">✅ Benefits</th><th style="padding:8px;text-align:left;background:var(--red-bg);color:var(--red);font-weight:700;border-bottom:2px solid var(--red);">⚠️ Limitations</th></tr></thead><tbody><tr style="vertical-align:top;"><td style="padding:8px;">• Early defect detection<br>• Prevents common issues (syntax, uninit vars)<br>• Improves code quality + maintainability<br>• Reduces overall cost<br>• Immediate feedback per phase</td><td style="padding:8px;">• Cannot detect ALL defects (runtime crashes need dynamic testing)<br>• Depends on reviewer's skills (humans miss things)<br>• Time-consuming (multiple review sessions)<br>• No runtime environment (no perf data)<br>• Prone to human error</td></tr></tbody></table><p><strong>💡 7 Best Practices:</strong></p><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:12.5px;"><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;width:35%;">1. Define clear objectives</td><td style="padding:6px 8px;">"Verify course-registration prerequisite rules"</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">2. Develop checklists</td><td style="padding:6px 8px;">"Are all vars initialized? Max course limit = 5?"</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">3. Focus on high-risk areas</td><td style="padding:6px 8px;">Registration / payment > UI color themes</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">4. Train the team</td><td style="padding:6px 8px;">Devs trained on static analysis tools</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">5. Prevent execution delays</td><td style="padding:6px 8px;">Fix early → no surprise failures in system test</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:600;">6. Track review activities</td><td style="padding:6px 8px;">Log all defects + monitor resolution</td></tr><tr><td style="padding:6px 8px;font-weight:600;">7. Keep tools updated</td><td style="padding:6px 8px;">New vulnerability patterns appear monthly</td></tr></tbody></table><div class="zh-note">优点 5 条 + 缺点 5 条 + 最佳实践 7 条。核心：用清单 · 测高风险 · 早跟早改。</div>`},
{title:"📝 Defect Tracking + LMS Example",ref:"pp.98",content:`<p>Every static testing finding must be <strong>logged, assigned, and verified</strong>. Without tracking, static testing provides no real value.</p><p><strong>📋 Each defect entry contains:</strong></p><ul><li>📝 <strong>Description</strong> of the issue</li><li>🔧 <strong>Suggested corrective action</strong></li><li>📊 <strong>Status</strong>: Open / In Progress / Fixed / Closed</li><li>📅 <strong>Target completion date</strong></li></ul><p><strong>📚 LMS Example — defect tracking sheet:</strong></p><div style="background:var(--bg-warm);padding:14px 18px;border-radius:10px;margin:10px 0;font-size:13px;border-left:3px solid var(--orange);"><strong>During static testing of the LMS SRS, reviewers found:</strong><br>❌ Missing rule for "maximum books allowed per student"<br>❌ Incorrect rule: "students can borrow unlimited books"<br><br><strong>These defects are:</strong><br>① Logged in defect sheet<br>② Assigned to the BA for correction<br>③ Rechecked after fixing<br>④ Marked as <strong>Closed</strong></div><p><strong>🛠️ Tools:</strong> Simple = Excel spreadsheet · Complex = Jira / Azure DevOps / Linear / GitHub Issues.</p><div class="callout important"><strong>3 reasons tracking matters:</strong> ① Verify corrections actually happen ② Improve documentation quality permanently ③ Prevent the "I'll document it after coding" attitude that kills projects.</div><div class="zh-note">缺陷必须记录(描述+建议+状态+期限)。LMS 例子：发现"借书无上限"问题 → 登记 → 派给 BA → 修后复查 → 关闭。工具：Excel / Jira。</div>`},
{title:"🏥 LMS Activity: Find the Defects",ref:"Module 5",content:`<p>Apply everything you learned. Here's the actual Module 5 in-class activity.</p><div style="background:var(--bg-warm);padding:14px 18px;border-radius:10px;margin:12px 0;font-size:13.5px;border-left:3px solid var(--accent);"><strong style="color:var(--accent-dim);">📋 Scenario:</strong> Library Management System SRS has these 6 requirements. Find all defects.</div><table style="width:100%;border-collapse:collapse;margin:10px 0;font-size:13px;"><thead><tr style="background:var(--accent-bg);border-bottom:2px solid var(--accent);"><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);width:30px;">#</th><th style="padding:6px 8px;text-align:left;color:var(--accent-dim);">Requirement</th></tr></thead><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;">1</td><td style="padding:6px 8px;">The system shall allow users to borrow books from the library.</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;">2</td><td style="padding:6px 8px;">A user can borrow <strong>unlimited</strong> books at any time.</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;">3</td><td style="padding:6px 8px;">The system <strong>does not track due dates</strong> for borrowed books.</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;">4</td><td style="padding:6px 8px;">Books are <strong>automatically available</strong> for borrowing <strong>even if all copies are issued</strong>.</td></tr><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:6px 8px;font-weight:700;">5</td><td style="padding:6px 8px;">The system shall allow only registered students to borrow books.</td></tr><tr style="background:var(--bg-warm);"><td style="padding:6px 8px;font-weight:700;">6</td><td style="padding:6px 8px;">There is <strong>no restriction</strong> on returning books.</td></tr></tbody></table><div class="callout">👉 Try the <strong>Interactive tab → 🏥 LMS Defect Hunter</strong> to click each one and check if you found the defects.</div><div class="zh-note">实战练习：6 条 LMS 需求里找缺陷。点 Interactive 标签里的"LMS Defect Hunter"试试看，能找出几个？</div>`},
{title:"💎 Putting Static Testing in Perspective",ref:"pp.98",content:`<div class="callout important"><strong>Most frequently overlooked testing approach.</strong><br><br>The common misconception: <em>"static testing wastes time that could be spent designing or coding."</em><br><br>The reality: a few well-spent hours of static testing <strong>saves hundreds of hours</strong> of correcting code caused by poor documentation.</div><table style="width:100%;border-collapse:collapse;margin:14px 0;font-size:13px;"><tbody><tr style="border-bottom:1px solid var(--border-light);"><td style="padding:10px;background:var(--green-bg);font-weight:600;width:35%;color:var(--green);">💸 Cost ratio</td><td style="padding:10px;">2-4 hours static testing → saves 100+ hours of rework</td></tr><tr style="background:var(--bg-warm);border-bottom:1px solid var(--border-light);"><td style="padding:10px;background:var(--accent-bg);font-weight:600;color:var(--accent-dim);">📈 Defect potential</td><td style="padding:10px;">Catches the 85% of defects that originate UPSTREAM (recall Unit 1)</td></tr><tr><td style="padding:10px;background:var(--purple-bg);font-weight:600;color:var(--purple);">🎓 Course tie-in</td><td style="padding:10px;">Same lesson as Boehm's Rule (Unit 1), Bathtub Diagram (Unit 4)</td></tr></tbody></table><div class="zh-note">静态测试是最常被忽视、但 ROI 最高的测试。几小时静态测试 = 节省数百小时返工。和 Unit 1 的 Boehm 法则、Unit 4 的浴缸图一脉相承。</div>`}
],quiz:[
{type:"mc",q:"Static testing means testing:",options:["Software under peak workload conditions","Documentation and code WITHOUT executing the software","Code using automated test tools that execute it","Software from the user's perspective"],answer:1,explanation:"Static = 'not while running.' It tests documentation AND code by inspecting them, without execution."},
{type:"mc",q:"The primary goal of static testing is to:",options:["Measure software response time","Validate software behavior against requirements","Reduce defects by fixing documentation defects before code is written","Test security configurations"],answer:2,explanation:"Primary goal: reduce software defects by reducing UPSTREAM (documentation) defects. Recall: 85% of defects come from poor requirements/design."},
{type:"mc",q:"Which is the ONLY review technique where the AUTHOR tests their own document?",options:["Walkthrough","Inspection","Desk checking","Peer review"],answer:2,explanation:"Desk checking is self-review by the author. All other techniques (informal/walkthrough/peer/inspection) use independent reviewers."},
{type:"mc",q:"Which review technique is the MOST formal and rigorous?",options:["Desk checking","Informal review","Peer review","Inspection"],answer:3,explanation:"Inspection = trained independent reviewers + formal process + tracked defects. Most formal of the 5 techniques. Module 5 expanded the textbook's 3 techniques to 5 (adding Informal Review + Peer Review)."},
{type:"mc",q:"In the LMS scenario: SRS says max 5 books, but user guide says max 10. Which review focus area catches this?",options:["Completeness","Consistency","Scope Validation","Cosmetic cleanup"],answer:1,explanation:"Consistency = documents must not contradict each other. SRS vs user guide saying different limits = consistency defect."},
{type:"mc",q:"A 'Book Purchase' feature appears in the design doc, but the BRD never requested it. Which review focus area catches this?",options:["Completeness","Consistency","Scope Validation","Performance"],answer:2,explanation:"Scope Validation = no unnecessary features. Adding things nobody asked for = scope creep, even if the feature itself is well-built."},
{type:"sa",q:"List the 5 categories of documents that should be statically tested.",sampleAnswer:"1. Manager's documents (requirements, project plans)\n2. Developer's documents (use cases, designs, specs, source code)\n3. Tester's documents (test plans, test cases, environment specs)\n4. Administrator's documents (installation + operation guides)\n5. End user's documents (user guides, help screens, training manuals)",keywords:["manager","developer","tester","administrator","end user","requirements","test plan","user guide"]},
{type:"sa",q:"Name the 5 review techniques from Module 5, ordered from LEAST to MOST formal.",sampleAnswer:"1. Desk Checking (Very Low — author self-reviews)\n2. Informal Review (Low — share doc with team for quick feedback)\n3. Peer Review (Medium — one teammate reviews another's work)\n4. Walkthrough (High — structured group meeting)\n5. Inspection (Very High — trained independent reviewers, formal process)",keywords:["desk checking","informal","peer","walkthrough","inspection","formal"]},
{type:"mc",q:"Static analysis comes in 3 types. Which one counts the independent execution paths in code?",options:["Data flow","Control flow","Cyclomatic complexity","Branch coverage"],answer:2,explanation:"Cyclomatic complexity counts independent paths — used to determine the minimum test cases needed. Higher CC = more if/else = more tests required."},
{type:"mc",q:"Which of these defects can static analysis NOT catch?",options:["Unused variables","Dead code","Infinite loop in source","System crash under 1,000 concurrent users"],answer:3,explanation:"Static analysis catches: unused vars, dead code, infinite loops, undefined value vars, wrong syntax. Performance issues like crashes under load need DYNAMIC (load) testing."},
{type:"mc",q:"Which tool is specifically used for Python SECURITY (e.g., catching hardcoded passwords)?",options:["Checkstyle","Pylint","Bandit","ESLint"],answer:2,explanation:"Bandit = Python security tool. Pylint = Python style + logic. Checkstyle = Java. ESLint = JS/TS. SonarQube = enterprise multi-language."},
{type:"mc",q:"In the 7-step static testing process, when do you 'Collect Documents'?",options:["Step 1 (Planning)","Step 3","Step 5 (Code Reviews)","Step 7 (Analyze Results)"],answer:1,explanation:"7 steps: Planning → Prepare Artifacts → Collect Documents → Static Analysis (tools) → Code Reviews (manual) → Report Bugs → Analyze Results."},
{type:"mc",q:"Which of these is NOT one of the 5 limitations of static testing?",options:["Cannot detect runtime crashes","Depends on reviewer skills","Time-consuming","Costs more than dynamic testing"],answer:3,explanation:"Static testing is the CHEAPEST form of testing. The 5 limitations: can't detect all defects, depends on reviewer skills, time-consuming, no runtime environment, prone to human error."},
{type:"sa",q:"What is the recommended TWO-STEP approach when reviewing a document?",sampleAnswer:"Step 1: Cosmetic cleanup — fix spelling, grammar, punctuation, formatting. If the doc isn't clean, reviewers will proofread instead of evaluating content.\nStep 2: Content review using one of the 5 techniques (desk check / informal / peer / walkthrough / inspection) to find inconsistencies, missing requirements, scope creep, logic errors.",keywords:["cosmetic","spelling","grammar","content","desk","inspection","walkthrough","peer","informal"]},
{type:"mc",q:"SCENARIO: A BA quickly shares the SRS with developers via email. A developer spots a missing login requirement within minutes. Which technique is this?",options:["Inspection","Informal Review","Walkthrough","Desk Checking"],answer:1,explanation:"Informal Review = fast and easy, share doc with team for quick feedback. Mainly for early defect detection + knowledge sharing. Walkthrough requires a structured meeting; inspection requires trained reviewers + formal process."},
{type:"mc",q:"SCENARIO: A modern dev team uses GitHub. Every pull request triggers SonarQube + ESLint to scan the code. What is this technique called in 2007 textbook terms?",options:["Performance testing","Static analysis","Black box testing","Functional testing"],answer:1,explanation:"Static analysis = examining code WITHOUT executing it, usually via automated tools. SonarQube / ESLint / Pylint / Bandit all do this. Modern CI/CD automates what was manual in 2007."},
{type:"sa",q:"In the LMS Activity, what defects can you find in: 'A user can borrow unlimited books at any time'?",sampleAnswer:"Multiple defects: (1) Inconsistency — most libraries limit borrowing, this contradicts typical business rules. (2) Missing rule — no max limit means students could empty the library. (3) Scope concern — 'unlimited' contradicts the need to track + return inventory. The corrected requirement should specify a maximum (e.g., max 5 books per student).",keywords:["unlimited","max","limit","inconsistency","missing","scope","corrected"]},
{type:"sa",q:"What 4 fields must every static-testing defect entry contain in the tracking sheet?",sampleAnswer:"1. Description of the issue (what's wrong)\n2. Suggested corrective action (how to fix)\n3. Status (Open / In Progress / Fixed / Closed)\n4. Target completion date (when it should be fixed)\nWithout tracking these, static testing provides no real value — defects get found but never fixed.",keywords:["description","suggested","corrective","status","open","closed","target","date"]},
{type:"mc",q:"Per the textbook, static testing is described as:",options:["The most expensive form of testing","The most frequently overlooked testing approach","Only useful for documentation","Replaced by automated tools"],answer:1,explanation:"Most frequently OVERLOOKED. Reality: 2-4 hours of static testing saves 100+ hours of rework. Catches the 85% of defects originating upstream (Unit 1 callback)."},
{type:"mc",q:"Which best practice involves listing what to check during a review?",options:["Define clear objectives","Develop checklists","Focus on high-risk areas","Track review activities"],answer:1,explanation:"Develop checklists = create lists like 'Are all variables initialized? Is max course limit = 5?' Borrowed from Boeing 299 lesson (Unit 3) — checklists prevent skipping steps."},
{type:"sa",q:"Why is static testing called the highest-ROI testing activity? Connect it to Boehm's Rule from Unit 1.",sampleAnswer:"Boehm's Rule (Unit 1): defects cost ~$1 in requirements, $50 in testing, $14,000 in production. Static testing catches defects in the requirements/design phase ($1 stage) BEFORE any code is written. A few hours of review prevents what would otherwise become hundreds of hours of debugging + rework + customer support. The textbook says it's 'most frequently overlooked' — meaning most teams leave huge ROI on the table.",keywords:["Boehm","cost","exponential","requirements","upstream","85%","overlooked","ROI","rework"]},
{type:"mc",q:"In the 7-step process, what's the typical split of defects found?",options:["Mostly UI bugs","~⅓ requirements, ~⅓ code, ~⅓ business logic","All performance","Mostly security"],answer:1,explanation:"Typical findings: ~10 requirements defects, ~5 code defects, ~3 business logic defects (per the SRS example) — roughly thirds across the 3 categories. Static testing surfaces all 3 types."}
]});

// ============================================================
// Unit 5: Interactive Widgets (LMS Defect Hunter + Review Technique Picker)
// ============================================================
INTERACTIVES[5] = function(el) {
  let u5Tab = 0;
  const tabs = [
    {key:'hunt',  icon:'🏥', label:'LMS Defect Hunter'},
    {key:'pick',  icon:'👥', label:'Review Technique Picker'}
  ];

  // ---------- Widget 1: LMS Defect Hunter ----------
  const lmsReqs = [
    {n:1, text:'The system shall allow users to borrow books from the library.',
     hasDefect:false,
     explain:'✅ This is a clear, valid requirement. No defects. (Could be more specific about WHO are "users" but that\'s not a defect — that\'s a refinement.)'},
    {n:2, text:'A user can borrow unlimited books at any time.',
     hasDefect:true,
     explain:'⚠️ Multiple defects: (1) "Unlimited" contradicts typical library business rules. (2) Missing maximum limit (e.g., 5). (3) Inconsistency — most LMS have borrowing caps. Fix: "A registered user can borrow up to 5 books at a time."'},
    {n:3, text:'The system does not track due dates for borrowed books.',
     hasDefect:true,
     explain:'⚠️ Defect: Missing core functionality. Without due-date tracking, you can\'t calculate fines, send reminders, or know when books are overdue. Fix: "The system shall track a due date for every borrowed book."'},
    {n:4, text:'Books are automatically available for borrowing even if all copies are issued.',
     hasDefect:true,
     explain:'⚠️ Logical defect: physically impossible. If all copies are issued, none are available. Fix: "If all copies are issued, the system shall display 0 available and prevent borrowing until a return."'},
    {n:5, text:'The system shall allow only registered students to borrow books.',
     hasDefect:false,
     explain:'✅ Clear, testable requirement. (Could specify "registered AND active" to handle suspended accounts, but that\'s refinement, not a defect.)'},
    {n:6, text:'There is no restriction on returning books.',
     hasDefect:true,
     explain:'⚠️ Ambiguous: "no restriction" is too broad. Can returns happen at 3 AM? Can damaged books be returned without inspection? Fix: "Returns are accepted during library hours; damaged books require staff inspection."'}
  ];
  let lmsPicks = {};   // {reqNum: 'defect'|'clean'}
  let lmsRevealed = false;

  function renderHunt() {
    const total = lmsReqs.length;
    const totalDefects = lmsReqs.filter(r => r.hasDefect).length;
    let picked = 0, correctPicks = 0, falsePos = 0, missed = 0;
    lmsReqs.forEach(r => {
      const p = lmsPicks[r.n];
      if (p === 'defect') {
        picked++;
        if (r.hasDefect) correctPicks++; else falsePos++;
      } else if (p === 'clean' && r.hasDefect) {
        missed++;
      }
    });
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">📋 Read each LMS requirement. Click 🚩 if you suspect a defect, ✅ if it\'s clean. Reveal answers when done.</p>';
    h += '<div style="display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap;">';
    h += '<button onclick="window._u5reveal()" '+(lmsRevealed?'disabled':'')+' style="cursor:pointer;padding:8px 16px;border-radius:8px;border:none;background:var(--accent);color:#fff;font-weight:600;font-size:13px;opacity:'+(lmsRevealed?0.5:1)+';">🔍 Reveal Answers</button>';
    h += '<button onclick="window._u5reset()" style="cursor:pointer;padding:8px 16px;border-radius:8px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-size:13px;">🔁 Reset</button>';
    h += '</div>';
    // Requirements list
    lmsReqs.forEach(r => {
      const p = lmsPicks[r.n];
      let bg = 'var(--surface)', border = 'var(--border-light)';
      if (lmsRevealed) {
        if (p === 'defect' && r.hasDefect)       { bg='var(--green-bg)'; border='var(--green)'; }
        else if (p === 'clean' && !r.hasDefect)  { bg='var(--green-bg)'; border='var(--green)'; }
        else if (p === 'defect' && !r.hasDefect) { bg='var(--orange-bg)'; border='var(--orange)'; }
        else if (p === 'clean' && r.hasDefect)   { bg='var(--red-bg)'; border='var(--red)'; }
        else if (r.hasDefect)                    { bg='rgba(252,232,231,0.4)'; border='var(--red)'; }
      } else if (p) {
        bg='var(--bg-warm)'; border='var(--accent)';
      }
      h += '<div style="background:'+bg+';border:2px solid '+border+';border-radius:10px;padding:12px 16px;margin-bottom:8px;transition:all .2s;">';
      h += '<div style="display:flex;align-items:flex-start;gap:12px;">';
      h += '<div style="font-size:18px;font-weight:700;color:var(--accent);min-width:24px;">'+r.n+'.</div>';
      h += '<div style="flex:1;font-size:13.5px;color:var(--text);line-height:1.5;">'+r.text+'</div>';
      h += '<div style="display:flex;gap:4px;">';
      const dSel = p === 'defect';
      const cSel = p === 'clean';
      h += '<button onclick="window._u5pick('+r.n+',\'defect\')" '+(lmsRevealed?'disabled':'')+' style="cursor:'+(lmsRevealed?'default':'pointer')+';padding:6px 10px;border-radius:6px;border:2px solid '+(dSel?'var(--red)':'var(--border-light)')+';background:'+(dSel?'var(--red-bg)':'var(--surface)')+';color:'+(dSel?'var(--red)':'var(--text-dim)')+';font-size:14px;font-weight:600;transition:all .15s;">🚩</button>';
      h += '<button onclick="window._u5pick('+r.n+',\'clean\')" '+(lmsRevealed?'disabled':'')+' style="cursor:'+(lmsRevealed?'default':'pointer')+';padding:6px 10px;border-radius:6px;border:2px solid '+(cSel?'var(--green)':'var(--border-light)')+';background:'+(cSel?'var(--green-bg)':'var(--surface)')+';color:'+(cSel?'var(--green)':'var(--text-dim)')+';font-size:14px;font-weight:600;transition:all .15s;">✅</button>';
      h += '</div></div>';
      if (lmsRevealed) {
        h += '<div style="margin-top:10px;padding-top:10px;border-top:1px dashed var(--border-light);font-size:12.5px;color:var(--text);line-height:1.6;">'+r.explain+'</div>';
      }
      h += '</div>';
    });
    // Score panel
    if (lmsRevealed) {
      h += '<div style="margin-top:14px;padding:14px 18px;border-radius:10px;background:var(--accent-bg);border:2px solid var(--accent);">';
      h += '<div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:1px;color:var(--accent-dim);margin-bottom:8px;">📊 Your Score</div>';
      h += '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;font-size:13px;">';
      h += '<div><div style="font-size:24px;font-weight:700;color:var(--green);">'+correctPicks+'/'+totalDefects+'</div><div style="color:var(--text-dim);font-size:11px;">Defects Found</div></div>';
      h += '<div><div style="font-size:24px;font-weight:700;color:var(--red);">'+missed+'</div><div style="color:var(--text-dim);font-size:11px;">Defects Missed</div></div>';
      h += '<div><div style="font-size:24px;font-weight:700;color:var(--orange);">'+falsePos+'</div><div style="color:var(--text-dim);font-size:11px;">False Alarms</div></div>';
      h += '<div><div style="font-size:24px;font-weight:700;color:var(--blue);">'+Math.round((correctPicks/totalDefects)*100)+'%</div><div style="color:var(--text-dim);font-size:11px;">Detection Rate</div></div>';
      h += '</div></div>';
    }
    return h;
  }
  window._u5pick = function(n, p){ lmsPicks[n] = (lmsPicks[n] === p ? null : p); rerender(); };
  window._u5reveal = function(){ lmsRevealed = true; rerender(); };
  window._u5reset = function(){ lmsPicks = {}; lmsRevealed = false; rerender(); };

  // ---------- Widget 2: Review Technique Picker ----------
  const revScenarios = [
    {scen:'A Business Analyst finishes the SRS, runs spell-check, then reads it once herself to catch any obvious mistakes before sharing.',
     correct:0,
     explain:'Desk Checking — the AUTHOR reviews their own document. Very low formality. The only review type where author = reviewer.'},
    {scen:'A BA shares the SRS via Slack to 4 developers. One spots a missing login requirement within 10 minutes.',
     correct:1,
     explain:'Informal Review — fast and easy distribution to team members for quick feedback. Low formality, mainly for early defect detection + knowledge sharing.'},
    {scen:'Junior developer Alice writes a module. Senior developer Bob reviews her code and finds a missing fee-calculation rule.',
     correct:2,
     explain:'Peer Review — one teammate reviews another\'s work. Medium formality. Common in modern GitHub Pull Request workflows.'},
    {scen:'The team schedules a 2-hour meeting where the author presents each section of the SRS step-by-step. Members ask questions and identify gaps in logic.',
     correct:3,
     explain:'Walkthrough — structured group meeting, step-by-step coverage. High formality. Excellent for finding missing functionality + business rule gaps.'},
    {scen:'The QA manager assigns trained independent reviewers (not on the project) to formally inspect the SRS. They follow a checklist and document all defects.',
     correct:4,
     explain:'Inspection — most formal technique. Trained independent reviewers, formal process, tracked defects. The "gold standard" for critical projects.'}
  ];
  const revTechniques = [
    {key:0, label:'📝 Desk Checking',   color:'var(--orange)'},
    {key:1, label:'📤 Informal Review', color:'var(--blue)'},
    {key:2, label:'👫 Peer Review',     color:'var(--green)'},
    {key:3, label:'🚶 Walkthrough',     color:'var(--purple)'},
    {key:4, label:'🔍 Inspection',      color:'var(--red)'}
  ];
  let revSel = 0;
  let revPick = null;

  function renderPick() {
    const s = revScenarios[revSel];
    let h = '<p style="font-size:13px;color:var(--text-dim);margin-bottom:12px;">Read each scenario and pick which of the 5 review techniques is being described.</p>';
    h += '<div style="display:flex;gap:6px;margin-bottom:14px;flex-wrap:wrap;align-items:center;">';
    h += '<span style="font-size:12px;color:var(--text-dim);">Scenario:</span>';
    revScenarios.forEach((_,i)=>{
      const sel = i===revSel;
      h += '<button onclick="window._u5rev('+i+')" style="cursor:pointer;width:32px;height:28px;border-radius:6px;border:2px solid '+(sel?'var(--accent)':'var(--border-light)')+';background:'+(sel?'var(--accent-bg)':'var(--surface)')+';color:'+(sel?'var(--accent-dim)':'var(--text-dim)')+';font-weight:700;font-size:12px;transition:all .15s;">'+(i+1)+'</button>';
    });
    h += '</div>';
    h += '<div style="background:var(--bg-warm);padding:16px 20px;border-radius:10px;font-size:13.5px;margin-bottom:14px;border-left:3px solid var(--accent);line-height:1.7;"><strong style="color:var(--accent-dim);">📋 Scenario '+(revSel+1)+':</strong> '+s.scen+'</div>';
    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px;">';
    revTechniques.forEach(t => {
      let bg='var(--surface)', border='var(--border-light)', color='var(--text-dim)';
      if (revPick !== null) {
        if (t.key === s.correct) { bg='var(--green-bg)'; border='var(--green)'; color='var(--green)'; }
        else if (t.key === revPick) { bg='var(--red-bg)'; border='var(--red)'; color='var(--red)'; }
      }
      h += '<button onclick="window._u5revPick('+t.key+')" '+(revPick!==null?'disabled':'')+' style="cursor:'+(revPick!==null?'default':'pointer')+';padding:10px 14px;border-radius:8px;border:2px solid '+border+';background:'+bg+';color:'+color+';font-weight:600;font-size:13px;text-align:left;transition:all .15s;">'+t.label+(revPick!==null && t.key===s.correct?' ✓':'')+(revPick!==null && t.key===revPick && t.key!==s.correct?' ✗':'')+'</button>';
    });
    h += '</div>';
    if (revPick !== null) {
      const ok = revPick === s.correct;
      h += '<div style="padding:14px 18px;border-radius:10px;background:'+(ok?'var(--green-bg)':'var(--orange-bg)')+';border:2px solid '+(ok?'var(--green)':'var(--orange)')+';font-size:13px;color:var(--text);"><strong style="color:'+(ok?'var(--green)':'var(--orange)')+';">'+(ok?'✅ Correct!':'⚠️ Not quite — see the highlighted correct answer.')+'</strong><br><br>'+s.explain+'</div>';
    } else {
      h += '<div style="padding:12px 16px;border-radius:8px;background:var(--surface2);font-size:12.5px;color:var(--text-dim);">👆 Pick a technique to see if it matches.</div>';
    }
    return h;
  }
  window._u5rev = function(i){ revSel=i; revPick=null; rerender(); };
  window._u5revPick = function(k){ revPick=k; rerender(); };

  // ---------- Main render with tabs ----------
  function rerender() {
    let h = '<div style="display:flex;gap:2px;margin-bottom:18px;background:var(--surface2);padding:3px;border-radius:10px;width:fit-content;border:1px solid var(--border-light);">';
    tabs.forEach((t,i) => {
      const active = i===u5Tab;
      h += '<button onclick="window._u5tab('+i+')" style="cursor:pointer;padding:8px 16px;border-radius:8px;border:none;background:'+(active?'var(--accent)':'transparent')+';color:'+(active?'#fff':'var(--text-dim)')+';font-size:13px;font-weight:600;transition:all .15s;">'+t.icon+' '+t.label+'</button>';
    });
    h += '</div>';
    h += '<div style="animation:u5fade 0.3s ease-out;">';
    if (u5Tab===0) h += renderHunt();
    else h += renderPick();
    h += '</div>';
    h += '<style>@keyframes u5fade{from{opacity:0;transform:translateX(-8px);}to{opacity:1;transform:translateX(0);}}</style>';
    el.innerHTML = h;
  }
  window._u5tab = function(i){ u5Tab=i; rerender(); };
  rerender();
};

